        let keyAttributes: [String: Any] = [
            kSecAttrKeyType as String: kSecAttrKeyTypeAES,
            kSecAttrKeySizeInBits as String: 256
        ]
        var error: Unmanaged<CFError>?
        return SecKeyCreateRandomKey(keyAttributes as CFDictionary, &error)
    }
    
